14.8.5 多母集団IRT（測定不変性の検討）


コード
pacman::p_load(mirt, dplyr)
data(SAT12)
SAT12[SAT12 == 8] &lt;- 5

# 仮の群変数（実務では属性データから作成）
set.seed(2024)
group &lt;- sample(c("G1", "G2"), nrow(SAT12), replace = TRUE)

# 各群で全カテゴリが観測されている項目のみを使用（識別性の確保）
# SAT12 はデータフレーム（列のリスト）の場合があるため、全体のカテゴリ集合を得る際は
# ベクトル化してから整数化する
K &lt;- sort(unique(stats::na.omit(as.integer(unlist(SAT12)))))
has_all_cats &lt;- function(x, cats) all(cats %in% unique(x[!is.na(x)]))
good_items &lt;- sapply(seq_len(ncol(SAT12)), function(j){
  g1 &lt;- has_all_cats(SAT12[group=='G1', j], K)
  g2 &lt;- has_all_cats(SAT12[group=='G2', j], K)
  g1 && g2
})

SAT12_bal &lt;- SAT12[, good_items, drop = FALSE]

# それでも厳しい場合は緩和（各群で少なくとも2カテゴリ以上）
if (ncol(SAT12_bal) == 0) {
  has_min_cats &lt;- function(x, m=2) length(unique(x[!is.na(x)])) &gt;= m
  good_items2 &lt;- sapply(seq_len(ncol(SAT12)), function(j){
    g1 &lt;- has_min_cats(SAT12[group=='G1', j], 2)
    g2 &lt;- has_min_cats(SAT12[group=='G2', j], 2)
    g1 && g2
  })
  SAT12_bal &lt;- SAT12[, good_items2, drop = FALSE]
}

if (ncol(SAT12_bal) &gt;= 3) {
  # Configural（構成）: 群平均/分散は等値（既定）、項目パラメータは自由
  mod_config &lt;- multipleGroup(SAT12_bal, 1, group = group, itemtype = 'graded')

  # Metric（傾き等値）
  mod_metric &lt;- multipleGroup(SAT12_bal, 1, group = group, itemtype = 'graded',
                              invariance = c('slopes'))

  # Scalar（閾値等値）
  mod_scalar &lt;- multipleGroup(SAT12_bal, 1, group = group, itemtype = 'graded',
                              invariance = c('slopes', 'intercepts'))

  # モデル比較（尤度比・情報量規準）
  anova(mod_config, mod_metric, mod_scalar)
} else {
  message('多母集団モデルの識別に十分な項目が確保できなかったためスキップ（各群のカテゴリ分布を確認）')
}


             AIC SABIC    HQ   BIC logLik       X2   df   p
mod_config 39081 39435 39577 40356 -19250                  
mod_metric 39063 39382 39510 40211 -19271  -40.454  -29 NaN
mod_scalar 38956 39133 39204 39593 -19333 -124.629 -116 NaN


ポイント：Configural → Metric → Scalarの順に制約を強め、適合の劣化が小さければ測定不変性が支持されます。ポリトマスでは「intercepts」は閾値（thresholds）に対応します。

15.12 生成データ（audio_generation.py）をRで一括解析（ネイティブパイプ）
以下は、Pythonのaudio_generation.pyで作成された最小データセット（./audio_dataset）を、Rで読み込み→記述統計→F0推定→集約保存する最小パイプラインです。R 4.1+ のネイティブパイプ（|&gt;）を使用しています。

15.12.1 ステップ

メタデータCSVの読み込み（ファイルパスを取得）
wavの標準前処理（モノラル化・正規化）
記述統計（duration/RMS/ZCR/スペクトル重心）
F0（fund）を持続母音は中央区間、文は全区間で中央値推定
テーブルを保存して後続（GLMMなど）へ

以下のパイプラインでは、Pythonの audio_generation.py で生成した最小データセットをRで一括処理します。メタデータCSVの読み込み → wavの前処理（モノラル化・正規化）→ 記述統計の算出 → F0の中央値推定 → テーブルの保存、という流れを R 4.1+ のネイティブパイプ（|&gt;）で記述しています。保存した特徴量テーブルは、そのまま GLMM や階層ベイズの入力データとして使えます。


コード
# このコードは存在チェックを行うため、ビルド環境に音声がなくても安全に動きます
if (file.exists("audio_dataset/metadata/metadata.csv")) {

  # 1) メタデータ読み込み
  md &lt;- read.csv("audio_dataset/metadata/metadata.csv", stringsAsFactors = FALSE)

  # 2) 前処理：モノラル化→正規化
  read_mono_norm &lt;- function(path) {
    w &lt;- readWave(path)
    if (w@stereo) w &lt;- mono(w, which = "left")
    tuneR::normalize(w, unit = "16", center = TRUE)
  }

  # 3) 記述統計：長さ・RMS・ZCR・スペクトル重心
  describe_wav &lt;- function(w) {
    dur_sec &lt;- length(w@left) / w@samp.rate
    rms_amp &lt;- seewave::rms(w)
    zcr_val &lt;- seewave::zcr(w)
    sp      &lt;- meanspec(w, f = w@samp.rate, wl = 1024, plot = FALSE)
    cent    &lt;- specprop(sp, f = w@samp.rate)$cent
    tibble(duration = dur_sec, rms = as.numeric(rms_amp),
           zcr = as.numeric(zcr_val), centroid = as.numeric(cent))
  }

  # 4) F0中央値（fund）：持続母音は中央50%区間、文は全区間
  f0_median &lt;- function(w, from = 0, to = NULL, fmax = 350) {
    s   &lt;- w@samp.rate
    dur &lt;- length(w@left) / s
    if (is.null(to)) { from &lt;- 0; to &lt;- dur }
    out &lt;- tryCatch(
      seewave::fund(w, f = s, ovlp = 50, from = from, to = to,
                    threshold = 5, fmax = fmax, plot = FALSE),
      error = function(e) NULL
    )
    if (is.null(out)) return(NA_real_)
    # 出力構造に依存せず中央値を取得
    vals &lt;- tryCatch({
      if (is.data.frame(out) || is.matrix(out)) as.numeric(out[, ncol(out)])
      else if (is.list(out) && !is.null(out$ff)) as.numeric(out$ff)
      else numeric(0)
    }, error = function(e) numeric(0))
    if (length(vals)) stats::median(vals, na.rm = TRUE) else NA_real_
  }

  # 5) 1レコードの特徴抽出
  extract_features &lt;- function(rec) {
    w &lt;- read_mono_norm(rec$filepath)
    s &lt;- w@samp.rate
    dur &lt;- length(w@left) / s
    stats &lt;- describe_wav(w)
    f0 &lt;- if (rec$task == "sustained_vowel")
      f0_median(w, from = dur*0.25, to = dur*0.75, fmax = 350) else f0_median(w, fmax = 350)
    dplyr::bind_cols(as_tibble(rec), stats, tibble(f0 = f0))
  }

  # 6) すべての行に適用（ネイティブパイプ＋baseのlapply）
  features &lt;- (
    md |&gt;
      (
        function(df) lapply(seq_len(nrow(df)), function(i) extract_features(df[i, , drop = FALSE]))
      )() |&gt;
      dplyr::bind_rows()
  )

  # 7) 持続母音の概要（例）
  features |&gt;
    dplyr::filter(task == "sustained_vowel") |&gt;
    dplyr::group_by(item) |&gt;
    dplyr::summarise(n = dplyr::n(),
                     mean_f0 = mean(f0, na.rm = TRUE),
                     sd_f0   = sd(f0, na.rm = TRUE),
                     mean_centroid = mean(centroid, na.rm = TRUE), .groups = "drop") |&gt;
    gt() |&gt;
    tab_header(title = "Sustained vowels: F0/spectral centroid summary")

  # 8) 文タイプのF0（例）
  features |&gt;
    dplyr::filter(task == "sentence") |&gt;
    dplyr::mutate(type = dplyr::coalesce(sentence_type, "unknown")) |&gt;
    dplyr::group_by(type) |&gt;
    dplyr::summarise(n = dplyr::n(),
                     mean_f0 = mean(f0, na.rm = TRUE),
                     sd_f0   = sd(f0, na.rm = TRUE), .groups = "drop") |&gt;
    gt() |&gt;
    tab_header(title = "Sentence: F0 summary (by type)")

  # 9) 保存
  write.csv(features, "audio_dataset/metadata/audio_features.csv", row.names = FALSE)

} else {
  message("audio_dataset が見つかりませんでした。先に Python の audio_generation.py を実行してください。")
}








GLMM への橋渡し



保存した audio_features.csv を metadata.csv と結合し、話者（Participant）やアイテム（Item）を乱効果にしてGLMM/階層ベイズへ展開できます。F0やフォルマントは連続、正誤は二値として第6章のレシピがそのまま適用できます。

16.4 都道府県名の正規化（名寄せ）
形状データの都道府県名と、分析対象の指標データの都道府県名は、そのままでは一致しないことがあります。全角/半角、余分な空白、末尾の「都・道・府・県」の有無といった表記の揺れが原因です。以下の norm_pref() 関数は、この揺れを吸収して名寄せを可能にします。


コード
# 正規化関数：全角/半角・空白・末尾の都/道/府/県の扱い
norm_pref &lt;- function(x){
  x |&gt;
    stringi::stri_trans_nfkc() |&gt;
    stringr::str_replace_all("\\s+", "") |&gt;
    stringr::str_replace("(東京都|北海道|京都府|大阪府)$", "") |&gt;
    stringr::str_replace("県$", "")
}

# 形状側の正規化キー
jpn_key &lt;- pref_sf |&gt;
  st_drop_geometry() |&gt;
  transmute(pref_name,
            pref_key = norm_pref(pref_name))








コードの読み方（パイプチェーン）



本章のRコードでは |&gt; （ネイティブパイプ）を多用します。これは「左辺の結果を右辺の関数の第1引数に渡す」操作です。
# 以下の2つは同じ意味:
result &lt;- f(g(h(x)))        # 入れ子（内側から読む）
result &lt;- x |&gt; h() |&gt; g() |&gt; f()  # パイプ（左から右へ順に読む）
norm_pref() の中身を読むと: (1) NFKC正規化（全角→半角統一）→ (2) 空白除去 → (3) 「東京都/北海道/京都府/大阪府」の除去 → (4) 末尾の「県」の除去、という一連の処理を上から下へ読めます。








名寄せのポイント




全角/半角や余分な空白、末尾の「都・道・府・県」を揃えると結合ミスが激減する。
実データに旧字体表記（例:「鋏」→「挟」）や略称が混ざる場合は、norm_pref() に辞書置換を追加する。
名寄せの成功は、次のステップの anti_join() でゼロ件になることで検証する。

16.8 空間自己相関の初歩（Moran’s I）

16.8.1 なぜ空間自己相関を考える必要があるのか
コロプレス図を眺めて「高スコアの都道府県が集まっているように見える」と感じたとしても、それだけでは科学的な主張にはなりません。ランダムなデータでも、たまたまそう見えるパターンが出現することがあります。Moran’s I は、観察された空間パターンが偶然で説明できるかどうかを統計的に検定する指標です。
直感的には、Moran’s I はPearson の相関係数 \(r\) の空間版です。

Pearson の \(r\): 2つの変数 \(X\) と \(Y\) の間の線形関連の強さを測る。
Moran’s \(I\): ある地点の値と、その隣接地域の加重平均値との間の線形関連を測る。

\(I &gt; 0\) ならば、似た値が近接に集まる傾向（正の空間自己相関）。\(I &lt; 0\) ならば、異なる値が隣り合う傾向。\(I \approx 0\) ならば、空間的にランダムな分布です。






英語教育研究にとっての意味



空間自己相関が存在する場合、以下の2つの含意があります。

統計的な問題: 通常のOLS回帰は「観測が独立」を前提とする。空間相関があると標準誤差が過小になり、p値が不当に小さくなる（第一種の過誤率が増える）。次章で扱う空間回帰モデルが必要になる場面。
実質的な関心: 高い英語力が地理的にクラスタしているなら、何がそのパターンを生んでいるのか。地域経済？教育投資の歴史？教員の流動性？空間パターンの存在自体が、新たな研究課題を提起する。





16.8.2 グローバル Moran’s I の計算


コード
dat_moran &lt;- pref_map |&gt;
  filter(!is.na(eng_score))

# 隣接（まず Queen）。孤立があれば k近傍で補完し、zero.policy を有効化
nb &lt;- spdep::poly2nb(dat_moran, queen = TRUE)
deg &lt;- spdep::card(nb)
augmented &lt;- FALSE
if (any(deg == 0)) {
  coords &lt;- sf::st_coordinates(sf::st_centroid(dat_moran))
  k &lt;- 1
  repeat {
    nb_knn &lt;- spdep::knn2nb(spdep::knearneigh(coords, k = k))
    nb &lt;- spdep::union.nb(nb, nb_knn)
    if (all(spdep::card(nb) &gt; 0) || k &gt;= 8) break
    k &lt;- k + 1
  }
  augmented &lt;- TRUE
}
lw &lt;- spdep::nb2listw(nb, style = 'W', zero.policy = TRUE)

# グローバル Moran（孤立許容）
moran_res &lt;- spdep::moran.test(dat_moran$eng_score, lw, zero.policy = TRUE)
moran_res



