# メタ分析結果をgt表に変換するヘルパー関数
rma_to_gt &lt;- function(fit, title = "Meta-Analysis Results") {
  s &lt;- coef(summary(fit))
  tbl &lt;- tibble::tibble(
    Term     = rownames(s),
    Estimate = s[, "estimate"],
    SE       = s[, "se"],
    z        = s[, "zval"],
    p        = s[, "pval"],
    CI_lower = s[, "ci.lb"],
    CI_upper = s[, "ci.ub"]
  )
  tbl |&gt;
    gt() |&gt;
    tab_header(title = title) |&gt;
    fmt_number(columns = c(Estimate, SE, z, CI_lower, CI_upper), decimals = 3) |&gt;
    fmt_number(columns = p, decimals = 4)
}
